def is_prime(n: int) -> bool:
    """Return whether n is prime. Assume n > 1 and is not a prime.
    >>> is_prime(13195)
    False
    >>> is_prime(2048)
    False
    """
    for i in range(2, n):
        if n % i == 0:
            return False
    return True

def largest_prime_factor_helper(n: int) -> int:
    """Return the largest prime factor of n. Assume n > 1 and is not a prime.
    >>> largest_prime_factor_helper(13195)
    29
    >>> largest_prime_factor_helper(2048)
    2
    """
    for i in range(2, n):
        if n % i == 0 and is_prime(i):
            return i
    return n

return largest_prime_factor_helper(n)

